import React from 'react';

function Home() {
  return (
    <div className="h-screen flex bg-gray-100">
      <div className="w-full flex flex-col justify-center items-center px-4 md:px-10 lg:px-20">
        {/* Text center */}
        <div className="text-center mb-10">
          <h2 className="text-2xl sm:text-3xl md:text-4xl font-bold text-gray-800">
            ¡Los invitamos a celebrar nuestra boda!
          </h2>
          <h1 className="text-3xl sm:text-4xl md:text-5xl font-elegante text-gray-800">
            Anto & Kevin
          </h1>
          <a
            href="https://p02jvynd.forms.app/formularioinvitados"
            className="inline-block mt-5 px-4 py-2 bg-gray-700 text-white font-bold rounded hover:bg-gray-800"
          >
            Confirmar asistencia
          </a>
        </div>

        {/* Images */}
        <div className="grid grid-cols-2 gap-4 md:grid-cols-3 lg:grid-cols-4">
          <img
            className="rounded-lg object-cover w-full h-auto"
            src="/Foto1.HEIC"
            alt="Imagen 1"
          />
          <img
            className="rounded-lg object-cover w-full h-auto"
            src="/Foto2.HEIC"
            alt="Imagen 2"
          />
          <img
            className="rounded-lg object-cover w-full h-auto"
            src="/Foto3.JPEG"
            alt="Imagen 3"
          />
          <img
            className="rounded-lg object-cover w-full h-auto"
            src="/Foto4.JPEG"
            alt="Imagen 4"
          />
          {/* More images if needed */}
        </div>
      </div>
    </div>
  );
}

export default Home;
